import React, { useState } from "react";

import {
  BrowserRouter,
  Routes,
  Route,
  useNavigate,
  useParams,
} from "react-router-dom";

import emailjs from "@emailjs/browser";

import "./App.css";

const products = [
  {
    id: 1,
    name: "Camera",
    price: 50,
    category: "Electronics",
    location: "Auckland",
    available: 3,
    description:
      "Professional DSLR camera for events and shoots.",
  },

  {
    id: 2,
    name: "Drill Machine",
    price: 20,
    category: "Tools",
    location: "Wellington",
    available: 5,
    description:
      "Heavy duty drill machine for home and construction work.",
  },

  {
    id: 3,
    name: "Speaker",
    price: 35,
    category: "Electronics",
    location: "Christchurch",
    available: 4,
    description:
      "Bluetooth speaker for parties and events.",
  },

  {
    id: 4,
    name: "Projector",
    price: 45,
    category: "Electronics",
    location: "Auckland",
    available: 2,
    description:
      "HD projector for movies and presentations.",
  },
];

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [error, setError] =
    useState("");

  const validateLogin = () => {
    setError("");

    const savedEmail =
      localStorage.getItem(
        "userEmail"
      );

    const savedPassword =
      localStorage.getItem(
        "userPassword"
      );

    if (
      email === savedEmail &&
      password === savedPassword
    ) {
      emailjs.send(
        "service_gk91tep",
        "template_hqu6lt8",
        {
          user_email: email,
          time:
            new Date().toLocaleString(),
        },
        "omkPXdWy353_kaQ2s"
      );

      navigate("/search");
    } else {
      setError(
        "Incorrect email or password"
      );
    }
  };

  return (
    <div className="page">
      <div className="phone-card">

        <div className="top-shape"></div>

        <h1>Welcome</h1>

        <p className="subtitle">
          Sign in to continue
        </p>

        <div className="form">

          <label>Email</label>

          <input
            type="text"
            placeholder="Enter email"
            value={email}
            onChange={(e) =>
              setEmail(
                e.target.value
              )
            }
          />

          <label>Password</label>

          <input
            type="password"
            placeholder="Enter password"
            value={password}
            onChange={(e) =>
              setPassword(
                e.target.value
              )
            }
          />

          {error && (
            <p className="error">
              {error}
            </p>
          )}

          <p
            className="forgot"
            onClick={() =>
              navigate(
                "/forgot-password"
              )
            }
          >
            Forgot Password?
          </p>

          <button
            onClick={validateLogin}
          >
            Sign in
          </button>

          <p className="bottom-text">
            Don’t have Account?{" "}
            <span
              onClick={() =>
                navigate(
                  "/register"
                )
              }
            >
              Sign up
            </span>
          </p>

        </div>
      </div>
    </div>
  );
}

function Register() {
  const navigate = useNavigate();

  const [name, setName] =
    useState("");

  const [email, setEmail] =
    useState("");

  const [phone, setPhone] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [message, setMessage] =
    useState("");

  const registerUser = () => {
    if (
      !name ||
      !email ||
      !phone ||
      !password
    ) {
      setMessage(
        "Please fill all fields"
      );

      return;
    }

    localStorage.setItem(
      "userName",
      name
    );

    localStorage.setItem(
      "userEmail",
      email
    );

    localStorage.setItem(
      "userPhone",
      phone
    );

    localStorage.setItem(
      "userPassword",
      password
    );

    setMessage(
      "Registration Successful!"
    );

    setTimeout(() => {
      navigate("/");
    }, 1500);
  };

  return (
    <div className="page">
      <div className="phone-card">

        <div
          className="back-button"
          onClick={() =>
            navigate("/")
          }
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Create Account</h1>

        <div className="form">

          <label>Name</label>

          <input
            type="text"
            placeholder="Enter name"
            value={name}
            onChange={(e) =>
              setName(
                e.target.value
              )
            }
          />

          <label>Email</label>

          <input
            type="text"
            placeholder="Enter email"
            value={email}
            onChange={(e) =>
              setEmail(
                e.target.value
              )
            }
          />

          <label>Phone</label>

          <input
            type="text"
            placeholder="Enter phone"
            value={phone}
            onChange={(e) =>
              setPhone(
                e.target.value
              )
            }
          />

          <label>Password</label>

          <input
            type="password"
            placeholder="Enter password"
            value={password}
            onChange={(e) =>
              setPassword(
                e.target.value
              )
            }
          />

          {message && (
            <p className="success">
              {message}
            </p>
          )}

          <button
            onClick={registerUser}
          >
            Sign up
          </button>

        </div>
      </div>
    </div>
  );
}

function ForgotPassword() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">

        <div
          className="back-button"
          onClick={() =>
            navigate("/")
          }
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Reset Password</h1>

        <p className="subtitle">
          Contact admin to reset
          password
        </p>

        <div className="form">

          <button
            onClick={() =>
              navigate("/")
            }
          >
            Back to Login
          </button>

        </div>
      </div>
    </div>
  );
}

function SearchPage() {
  const navigate = useNavigate();

  return (
    <div className="search-page">

      <div className="search-header">

        <h2>
          Search Equipment
        </h2>

        <button
          className="logout-btn"
          onClick={() =>
            navigate("/")
          }
        >
          Logout
        </button>

      </div>

      <input
        className="search-input"
        type="text"
        placeholder="Search equipment..."
      />

      <div className="filter-buttons">

        <button>Camera</button>

        <button>Tools</button>

        <button>Electronics</button>

        <button>Projector</button>

      </div>

      <div className="product-list">

        {products.map((item) => (
          <div
            className="product-card"
            key={item.id}
          >

            <p className="available">
              {item.available} Available
            </p>

            <h3>{item.name}</h3>

            <p>
              ${item.price} / day
            </p>

            <button
              onClick={() =>
                navigate(
                  `/details/${item.id}`
                )
              }
            >
              View Details
            </button>

          </div>
        ))}

      </div>
    </div>
  );
}

function DetailsPage() {
  return <div>Details Page</div>;
}

function PaymentPage() {
  return <div>Payment Page</div>;
}

function App() {
  return (
    <BrowserRouter>

      <Routes>

        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/register"
          element={<Register />}
        />

        <Route
          path="/forgot-password"
          element={<ForgotPassword />}
        />

        <Route
          path="/search"
          element={<SearchPage />}
        />

        <Route
          path="/details/:id"
          element={<DetailsPage />}
        />

        <Route
          path="/payment"
          element={<PaymentPage />}
        />

      </Routes>

    </BrowserRouter>
  );
}

export default App;
